import React, { useState } from "react";
import {
  Box,
  Card,
  CardContent,
  TextField,
  Button,
  Typography,
  Grow,
} from "@mui/material";

// ForwardRef wrapper to ensure Grow has access to the DOM node
const LoginCard = React.forwardRef((props, ref) => (
  <Card ref={ref} sx={{ maxWidth: 400, mx: "auto", mt: 10 }}>
    <CardContent>
      <Typography variant="h5" gutterBottom>
        Login
      </Typography>
      <form onSubmit={props.onSubmit}>
        <TextField
          fullWidth
          margin="normal"
          label="Email"
          type="email"
          value={props.email}
          onChange={(e) => props.setEmail(e.target.value)}
        />
        <TextField
          fullWidth
          margin="normal"
          label="Password"
          type="password"
          value={props.password}
          onChange={(e) => props.setPassword(e.target.value)}
        />
        <Button
          fullWidth
          variant="contained"
          color="primary"
          type="submit"
          sx={{ mt: 2 }}
        >
          Sign In
        </Button>
      </form>
    </CardContent>
  </Card>
));

const Login = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showCard, setShowCard] = useState(false);

  const handleLogin = (e) => {
    e.preventDefault();
    // Your login logic here
    console.log("Logging in with:", email, password);
  };

  React.useEffect(() => {
    // Delay to simulate component mount transition
    const timer = setTimeout(() => setShowCard(true), 100);
    return () => clearTimeout(timer);
  }, []);

  return (
    <Box>
      <Grow
        in={showCard}
        timeout={500}
        // Safe callback to check if node is valid
        onEnter={(node) => {
          if (node) {
            console.log("Transition node:", node);
          }
        }}
      >
        <LoginCard
          email={email}
          setEmail={setEmail}
          password={password}
          setPassword={setPassword}
          onSubmit={handleLogin}
        />
      </Grow>
    </Box>
  );
};

export default Login;
